class Solution:
    def minMoves(self, nums):
        # Independent: explicit min then accumulate gaps one by one.
        m = nums[0]
        for x in nums:
            if x < m:
                m = x
        total = 0
        for x in nums:
            total += x - m
        return total

solutions.python:
class Solution:
    def minMoves(self, nums):
        mn = min(nums)
        return sum(x - mn for x in nums)

